import type React from 'react';

import * as ProgressPrimitive from '@radix-ui/react-progress';
import { cva, type VariantProps } from 'class-variance-authority';

import { cn } from '../utils/cn';

const progressVariants = cva(
  'relative w-full overflow-hidden rounded-full bg-surface',
  {
    variants: {
      size: {
        sm: 'h-1.5',
        md: 'h-2.5',
        lg: 'h-4',
      },
    },
    defaultVariants: {
      size: 'md',
    },
  }
);

/**
 * A progress bar indicating completion status.
 */
function Progress({
  className,
  size,
  value,
  children,
  ...props
}: React.ComponentProps<typeof ProgressPrimitive.Root> &
  VariantProps<typeof progressVariants>) {
  return (
    <ProgressPrimitive.Root
      data-slot="progress"
      className={cn(progressVariants({ size }), className)}
      value={value}
      {...props}
    >
      {children ?? <ProgressIndicator value={value} />}
    </ProgressPrimitive.Root>
  );
}

/**
 * The filled portion of the progress bar.
 */
function ProgressIndicator({
  className,
  value,
  ...props
}: React.ComponentProps<typeof ProgressPrimitive.Indicator> & {
  value?: number | null;
}) {
  return (
    <ProgressPrimitive.Indicator
      data-slot="progress-indicator"
      className={cn(
        'h-full bg-primary rounded-full transition-all duration-300',
        className
      )}
      style={{ transform: `translateX(-${100 - (value || 0)}%)` }}
      {...props}
    />
  );
}

export { Progress, ProgressIndicator, progressVariants };
